     1→#!/usr/bin/env bun
     2→/**
     3→ * PAI Installation Wizard
     4→ *
     5→ * Interactive setup that walks you through personalizing your PAI:
     6→ * - Sets your name and timezone
     7→ * - Names your AI assistant
     8→ * - Configures voice settings
     9→ * - Fixes permissions and starts services
    10→ *
    11→ * Usage:
    12→ *   bun run INSTALL.ts    # Run the interactive wizard
    13→ */
    14→
    15→import { existsSync, mkdirSync, readFileSync, writeFileSync, readdirSync } from 'fs';
    16→import { join } from 'path';
    17→import { homedir, userInfo } from 'os';
    18→import { execSync, spawn } from 'child_process';
    19→import * as readline from 'readline';
    20→
    21→// ANSI colors
    22→const c = {
    23→  reset: '\x1b[0m',
    24→  bold: '\x1b[1m',
    25→  blue: '\x1b[38;2;59;130;246m',
    26→  green: '\x1b[38;2;34;197;94m',
    27→  yellow: '\x1b[38;2;234;179;8m',
    28→  red: '\x1b[38;2;239;68;68m',
    29→  cyan: '\x1b[38;2;6;182;212m',
    30→  gray: '\x1b[38;2;100;116;139m',
    31→};
    32→
    33→// Paths
    34→const HOME = homedir();
    35→const CLAUDE_DIR = join(HOME, '.claude');
    36→const ZSHRC = join(HOME, '.zshrc');
    37→const VOICE_SERVER_DIR = join(CLAUDE_DIR, 'VoiceServer');
    38→const VOICE_SERVER_PORT = 8888;
    39→
    40→// Default voice IDs - ElevenLabs pre-made voices (work with any API key)
    41→// Reference: https://elevenlabs-sdk.mintlify.app/voices/premade-voices
    42→const DEFAULT_VOICES = {
    43→  male: 'pNInz6obpgDQGcFmaJgB',      // Adam (male)
    44→  female: '21m00Tcm4TlvDq8ikWAM',    // Rachel (female)
    45→  neutral: 'ErXwobaYiN019PkySvjV',   // Antoni (versatile male)
    46→};
    47→
    48→interface InstallConfig {
    49→  PRINCIPAL_NAME: string;
    50→  TIMEZONE?: string;
    51→  AI_NAME?: string;
    52→  CATCHPHRASE?: string;
    53→  VOICE_TYPE?: 'male' | 'female' | 'neutral';
    54→  ELEVENLABS_KEY?: string;
    55→  CUSTOM_VOICE_ID?: string;
    56→  PROJECTS_DIR?: string;
