    59→// ============================================================================
    60→// UTILITY FUNCTIONS
    61→// ============================================================================
    62→
    63→function print(msg: string) { console.log(msg); }
    64→function printSuccess(msg: string) { print(`  ${c.green}✓${c.reset} ${msg}`); }
    65→function printWarning(msg: string) { print(`  ${c.yellow}!${c.reset} ${msg}`); }
    66→function printError(msg: string) { print(`  ${c.red}✗${c.reset} ${msg}`); }
    67→function printInfo(msg: string) { print(`  ${c.gray}→${c.reset} ${msg}`); }
    68→
    69→function createReadline(): readline.Interface {
    70→  return readline.createInterface({
    71→    input: process.stdin,
    72→    output: process.stdout,
    73→  });
    74→}
    75→
    76→async function prompt(question: string, defaultValue?: string): Promise<string> {
    77→  const displayDefault = defaultValue ? ` ${c.gray}[${defaultValue}]${c.reset}` : '';
    78→  const rl = createReadline();
    79→
    80→  return new Promise((resolve) => {
    81→    rl.question(`  ${question}${displayDefault}: `, (answer) => {
    82→      rl.close();
    83→      resolve(answer.trim() || defaultValue || '');
    84→    });
    85→  });
    86→}
    87→
    88→async function promptChoice(question: string, choices: string[], defaultIdx = 0): Promise<number> {
    89→  print(`  ${question}`);
    90→  choices.forEach((choice, i) => {
    91→    const marker = i === defaultIdx ? `${c.cyan}→${c.reset}` : ' ';
    92→    print(`    ${marker} ${i + 1}. ${choice}`);
    93→  });
    94→
    95→  const rl = createReadline();
    96→  return new Promise((resolve) => {
    97→    rl.question(`  ${c.gray}Enter 1-${choices.length} [${defaultIdx + 1}]:${c.reset} `, (answer) => {
    98→      rl.close();
    99→      const num = parseInt(answer.trim()) || (defaultIdx + 1);
   100→      resolve(Math.max(0, Math.min(choices.length - 1, num - 1)));
   101→    });
   102→  });
   103→}
