   105→// ============================================================================
   106→// PERMISSIONS (chmod → chown → chmod)
   107→// ============================================================================
   108→
   109→function fixPermissions(targetDir: string): void {
   110→  const info = userInfo();
   111→
   112→  print('');
   113→  print(`${c.bold}Fixing permissions for ${info.username}${c.reset}`);
   114→  print(`${c.gray}─────────────────────────────────────────────────${c.reset}`);
   115→
   116→  try {
   117→    // Step 1: chmod first - make files accessible
   118→    execSync(`chmod -R 755 "${targetDir}"`, { stdio: 'pipe' });
   119→    printSuccess('Step 1: chmod -R 755 (make accessible)');
   120→
   121→    // Step 2: chown - change ownership to current user
   122→    execSync(`chown -R ${info.uid}:${info.gid} "${targetDir}"`, { stdio: 'pipe' });
   123→    printSuccess(`Step 2: chown -R to ${info.username}`);
   124→
   125→    // Step 3: chmod again - set final permissions
   126→    execSync(`chmod -R 755 "${targetDir}"`, { stdio: 'pipe' });
   127→    printSuccess('Step 3: chmod -R 755 (final permissions)');
   128→
   129→    // Make scripts executable
   130→    for (const pattern of ['*.ts', '*.sh', '*.hook.ts']) {
   131→      try {
   132→        execSync(`find "${targetDir}" -name "${pattern}" -exec chmod 755 {} \\;`, { stdio: 'pipe' });
   133→      } catch (e) { /* ignore */ }
   134→    }
   135→    printSuccess('Set executable permissions on scripts');
   136→
   137→  } catch (err: any) {
   138→    printError(`Permission fix failed: ${err.message}`);
   139→    print(`${c.yellow}Run: sudo chown -R $(whoami) ${targetDir}${c.reset}`);
   140→  }
   141→}
