   143→// ============================================================================
   144→// VOICE SERVER MANAGEMENT
   145→// ============================================================================
   146→
   147→function findRunningVoiceServers(): number[] {
   148→  try {
   149→    const result = execSync(`lsof -ti:${VOICE_SERVER_PORT}`, { encoding: 'utf-8', stdio: ['pipe', 'pipe', 'pipe'] });
   150→    return result.trim().split('\n').map(s => parseInt(s.trim())).filter(n => !isNaN(n));
   151→  } catch (e) {
   152→    return [];
   153→  }
   154→}
   155→
   156→function killVoiceServers(): void {
   157→  const pids = findRunningVoiceServers();
   158→  if (pids.length > 0) {
   159→    printInfo(`Killing ${pids.length} existing voice server(s)`);
   160→    for (const pid of pids) {
   161→      try {
   162→        execSync(`kill -9 ${pid}`, { stdio: 'pipe' });
   163→        printSuccess(`Killed process ${pid}`);
   164→      } catch (e) { /* ignore */ }
   165→    }
   166→  }
   167→}
   168→
   169→async function startVoiceServer(): Promise<boolean> {
   170→  const startScript = join(VOICE_SERVER_DIR, 'start.sh');
   171→  if (!existsSync(startScript)) {
   172→    printWarning('Voice server start script not found');
   173→    return false;
   174→  }
   175→
   176→  killVoiceServers();
   177→
   178→  try {
   179→    const child = spawn('bash', [startScript], {
   180→      detached: true,
   181→      stdio: 'ignore',
   182→      cwd: VOICE_SERVER_DIR,
   183→    });
   184→    child.unref();
   185→
   186→    await new Promise(resolve => setTimeout(resolve, 2000));
   187→
   188→    if (findRunningVoiceServers().length > 0) {
   189→      printSuccess('Voice server started');
   190→      return true;
   191→    } else {
   192→      printWarning('Voice server may not have started');
   193→      return false;
   194→    }
   195→  } catch (err: any) {
   196→    printError(`Failed to start voice server: ${err.message}`);
   197→    return false;
   198→  }
   199→}
