   264→function setupZshAlias(): void {
   265→  const aliasLine = `alias pai='bun ~/.claude/skills/PAI/Tools/pai.ts'`;
   266→  const marker = '# PAI alias';
   267→
   268→  try {
   269→    let content = existsSync(ZSHRC) ? readFileSync(ZSHRC, 'utf-8') : '';
