   616→async function main() {
   617→  const args = process.argv.slice(2);
   618→
   619→  // No args - launch without touching MCP config (use native /mcp commands)
   620→  if (args.length === 0) {
   621→    await cmdLaunch({});
   622→    return;
   623→  }
   624→
   625→  // Parse arguments
   626→  let mcp: string | undefined;
   627→  let resume = false;
   628→  let skipPerms = true;
   629→  let local = false;
   630→  let command: string | undefined;
   631→  let subCommand: string | undefined;
   632→  let subArg: string | undefined;
   633→  let promptText: string | undefined;
   634→  let wallpaperArgs: string[] = [];
   635→
   636→  for (let i = 0; i < args.length; i++) {
   637→    const arg = args[i];
   638→
   639→    switch (arg) {
   640→      case "-m":
   641→      case "--mcp":
   642→        const nextArg = args[i + 1];
   643→        // -m with no arg, or -m 0, or -m "" means no MCPs
   644→        if (!nextArg || nextArg.startsWith("-") || nextArg === "0" || nextArg === "") {
   645→          mcp = "none";
   646→          if (nextArg === "0" || nextArg === "") i++;
   647→        } else {
   648→          mcp = args[++i];
   649→        }
   650→        break;
   651→      case "-r":
   652→      case "--resume":
   653→        resume = true;
   654→        break;
   655→      case "--safe":
   656→        skipPerms = false;
   657→        break;
   658→      case "-l":
   659→      case "--local":
   660→        local = true;
   661→        break;
   662→      case "-v":
   663→      case "--version":
   664→      case "version":
   665→        command = "version";
   666→        break;
   667→      case "-h":
   668→      case "--help":
   669→      case "help":
   670→        command = "help";
   671→        break;
   672→      case "update":
   673→        command = "update";
   674→        break;
   675→      case "profiles":
   676→        command = "profiles";
   677→        break;
   678→      case "mcp":
   679→        command = "mcp";
   680→        subCommand = args[++i];
   681→        subArg = args[++i];
   682→        break;
   683→      case "prompt":
   684→      case "-p":
   685→        command = "prompt";
   686→        promptText = args.slice(i + 1).join(" ");
   687→        i = args.length; // Exit loop
   688→        break;
   689→      case "-w":
   690→      case "--wallpaper":
   691→        command = "wallpaper";
   692→        wallpaperArgs = args.slice(i + 1);
   693→        i = args.length; // Exit loop
   694→        break;
   695→      default:
   696→        if (!arg.startsWith("-")) {
   697→          // Might be an unknown command
   698→          error(`Unknown command: ${arg}. Use 'k help' for usage.`);
   699→        }
   700→    }
   701→  }
   702→
   703→  // Handle commands
   704→  switch (command) {
   705→    case "version":
   706→      await cmdVersion();
   707→      break;
   708→    case "help":
   709→      cmdHelp();
   710→      break;
   711→    case "update":
   712→      await cmdUpdate();
   713→      break;
   714→    case "profiles":
   715→      cmdProfiles();
   716→      break;
   717→    case "mcp":
   718→      if (subCommand === "list") {
   719→        cmdMcpList();
   720→      } else if (subCommand === "set" && subArg) {
   721→        setMcpProfile(subArg);
   722→      } else {
   723→        error("Usage: k mcp list | k mcp set <profile>");
   724→      }
   725→      break;
   726→    case "prompt":
   727→      if (!promptText) {
   728→        error("Usage: k prompt \"your prompt here\"");
   729→      }
   730→      await cmdPrompt(promptText);
   731→      break;
   732→    case "wallpaper":
   733→      cmdWallpaper(wallpaperArgs);
   734→      break;
   735→    default:
   736→      // Launch with options
   737→      await cmdLaunch({ mcp, resume, skipPerms, local });
   738→  }
   739→}
